@import url("https://fonts.googleapis.com/css2?family=Poppins:ital,wght@0,100;0,200;0,300;0,400;0,500;0,600;0,700;0,800;0,900;1,100;1,200;1,300;1,400;1,500;1,600;1,700;1,800;1,900&display=swap");
@import "variables";
@import "util";

@import "components/navbar";

@import "components/card";

@import "components/footer";

@import "sections/hero";
@import "sections/about";
@import "sections/portfolio";
@import "sections/contact";
@import "sections/links";
@import "sections/wallpapers";

// Reset styles
*,
*::after,
*::before {
  margin: 0;
  padding: 0;
  box-sizing: inherit;
}

html {
  font-size: 62.5%; // setting the root font size to be used with rem
  scroll-behavior: smooth;
}

body {
  background-color: $bg-color;
  color: $text-color;
  box-sizing: border-box;
  line-height: 1.7;
  font-family: "Poppins", sans-serif;
}

h1,
h2,
h3,
h4,
h5,
h6 {
  color: $white-color;
}

ul {
  list-style: none;
}

a {
  text-decoration: none;
  color: $link-color;

  &:hover {
    color: $hover-color-white;
  }
}

.tag {
  font-size: 1.2rem;
}

.nohover {
  pointer-events: none;
}

i {
  color: $text-color;
}

p {
  font-size: 1.6rem;
  color: $text-color;
}

main {
  min-height: calc(100vh - 22rem);
  padding-top: 9rem;
}

.container {
  max-width: 119rem;
  width: 85%;
  margin: 2.5rem auto;

  h1 {
    font-size: 4.5rem;
  }

  h2 {
    font-size: 2.5rem;
  }
}

section {
  padding: 5rem 0;
}

@media (max-width: 1000px) {
  .container {
    width: 90%;
  }
}

@media (max-width: 550px) {
  .container {
    width: 85%;
    h1 {
      font-size: 4rem;
    }
  }
}

@media (max-width: 380px) {
  .container {
    h1 {
      font-size: 3.3rem;
    }
    p {
      font-size: 1.5rem;
    }
  }
}

@media (max-width: 360px) {
  .container h1 {
    font-size: 3rem;
  }
  .line {
    margin-top: 3rem;
  }
  .p-email {
    margin-bottom: 1rem;
  }
}

@media (max-height: 740px) {
  .container-center {
    height: 60%;
  }
}

@media (max-height: 600px) {
  .container-center {
    height: 70%;
  }
}

sources.scss/_util.scss:
.break {
  display: block;
}

.hidden {
  display: none;
}

.bold {
  font-weight: 700;
  letter-spacing: 1.1;

  &-white {
    color: $white-color;
    font-weight: 600;
  }
}

.box-shadow {
  box-shadow: $box-shadow;
}

.line {
  border: 1px solid $text-color;
  opacity: 0.7;
  width: 100%;
  border-radius: $radius;
  margin: auto;
}

.underline {
  text-decoration: underline;

  &-white {
    color: $white-color;
  }
}

.btn {
  padding: 1rem 2rem;
  border-radius: $radius;
  margin-right: 2rem;
  font-weight: 500;
  font-size: 1.6rem;
  transition: all 0.2s ease;
  box-shadow: $box-shadow;
  display: inline-block;

  &:hover {
    transform: translateY(-1px);
  }

  &:active {
    transform: translateY(1px);
  }

  &--black {
    background-color: black;
    color: $white-color;
  }

  &--primary {
    background: $white-color;
    color: black;

    &:hover {
      color: rgba(0, 0, 0, 0.7);
      background-color: $hover-color-white;
    }
  }

  &--secondary {
    border: 1px solid $white-color;
    color: $white-color;
  }
}

.container-center {
  display: flex;
  height: 50%;
  flex-direction: column;
  align-items: center;
  justify-content: center;
}

.flex {
  display: flex;
}

sources.scss/components/_navbar.scss:
// Navbar
.navbar {
  position: fixed;
  width: 100%;
  background: $bg-color;
  z-index: 99;
  transition: all 0.6s ease;
  transition: visibility 0.6s ease;

  .hamburger {
    display: none;
    font-size: 2rem;

    i {
      color: $white-color;

      &:hover {
        color: $hover-color-white;
      }
      &:active {
        opacity: 0.9;
      }
    }
  }

  .flex {
    display: flex;
  }

  &__container {
    display: flex;
    justify-content: space-between;
    a {
      font-size: 1.6rem;
    }
  }

  &__menu {
    display: flex;
    // justify-content: center;

    li {
      // margin-right: 12px;
      padding: 1rem;
    }

    .btn {
      display: inline;
    }

    a {
      font-weight: 600;

      &:hover {
        border-bottom: 1px solid black;
      }
    }
  }

  &__logo {
    cursor: pointer;
    font-weight: 700;
    color: $white-color;
    text-align: center;
    a {
      color: $white-color;
      font-size: 3rem;

      &:hover {
        color: $hover-color-white;
      }
    }

    &__top-section {
      display: flex;
      align-items: center;
    }

    &__menu {
      flex-direction: column;
      display: none;

      .btn {
        display: block;
      }
    }
  }
}

@media (max-width: 900px) {
  .navbar {
    &__container.container {
      flex-direction: column;
      margin: 1.5rem auto;
    }

    &__top-section {
      display: flex;
      align-items: center;
      padding-bottom: 1rem;
    }
    .hamburger {
      display: block;
      margin-right: 2rem;
    }

    &__menu {
      flex-direction: column;
      display: none;

      .btn {
        display: block;
      }

      li:hover:not(:last-child) {
        background: #4b4b4b;

        a {
          color: $hover-color-white;

          &:hover {
            border: none;
          }
        }
      }
    }
  }
}

@media (max-width: 500px) {
  .navbar__logo a {
    font-size: 2.8rem;
  }
}

sources.scss/components/_card.scss:
// cards
.cards {
  display: flex;

  .card {
    background-color: white;
    margin: 0 1.1rem;
    padding: 3rem;
    text-align: left;
    border-radius: $radius;
    width: 33%;

    &__img {
      img {
        width: 100%;
      }
    }

    h3 {
      color: black;
      font-size: 2.2rem;
    }

    &__description {
      color: black;
      margin-bottom: 2rem;
    }

    & .underline {
      color: black;

      &:hover {
        color: $hover-color-black;
      }
    }

    &__cta {
      font-size: 1.5rem;
      font-weight: 500;

      &:hover {
        text-decoration: underline;
        color: gray;
      }
    }

    &__icons {
      display: flex;
      margin-bottom: 1.5rem;
    }

    &__icon {
      font-size: 3.8rem;
      margin-right: 1.5rem;

      i {
        color: gray;

        &:hover {
          color: black;
        }
      }
    }

    &__subheading {
      color: black;
      font-size: 1.7rem;
    }

    &__list {
      &-container {
        display: flex;
        justify-content: space-between;
      }
      list-style: disc;
      padding-left: 1.7rem;
      margin-bottom: 2rem;
      li {
        color: black;
        font-size: 1.4rem;
      }
    }
  }
}

@media (max-width: 1350px) {
  .card__list-container {
    flex-direction: column;
  }
}

@media (max-width: 1090px) {
  .cards {
    flex-direction: column;

    .card {
      width: 100%;
      margin: 1rem 0;
      text-align: center;

      &__list li {
        list-style: none;
      }

      &__icons {
        justify-content: center;
      }

      &__list {
        padding-left: 0;
        &-container {
          flex-direction: row;
          justify-content: center;
          div {
            padding: 1rem;
            display: flex;
            flex-direction: column;
            width: 20rem;

            li {
              list-style: none;
            }
          }
        }
      }
    }
  }
}

@media (max-width: 500px) {
  .cards {
    .card {
      padding: 2.5rem;
      &__description {
        margin-bottom: 1rem;
      }

      &__list-container {
        flex-direction: column;
        align-items: center;
      }
    }
  }
}

@media (max-width: 450px) {
  .cards {
    .card {
      width: 90%;
      margin-left: auto;
      margin-right: auto;
    }
  }
}

